import redis

# Create Redis connection
r = redis.Redis(host='localhost', port=6379, db=0)

def run_lua_script(lua_script, params):
    # Prepare and execute Lua script with parameters
    r.eval(lua_script, 1, *params)

if __name__ == "__main__":
    lua_script = input("Enter Lua script: ")
    params = eval(input("Enter parameters as Python list: "))
    run_lua_script(lua_script, params)